INSERT INTO store_settings(id,data) VALUES(1,'{"storeName":"Sharuu Universal Store","slogan":"Everything you need, in one place.","description":"A configurable multi-purpose online shop.","logo":"","primaryColor":"#0f172a","secondaryColor":"#d97706","currency":"BDT","currencySymbol":"৳","supportPhone":"+880 1700-000000","supportEmail":"support@example.com","address":"Bangladesh","heroTitle":"One Store. Every Possibility.","heroSubtitle":"Fashion, baby products, footwear, toys, electronics and more—managed from one admin panel.","heroImage":"https://images.unsplash.com/photo-1441986300917-64674bd600d8?auto=format&fit=crop&w=1800&q=85","heroButtonText":"Shop Now","announcement":"Free delivery on orders over ৳5,000","footerText":"© Sharuu Universal Store. All rights reserved.","footerDescription":"Premium products across fashion, baby, footwear, accessories, toys and electronics.","footerContactTitle":"Contact Us","footerBottomText":"Secure shopping · Fast delivery · Easy support","footerColumns":[{"title":"Shop"},{"title":"Information"}],"invoiceNote":"Thank you for shopping with Sharuu Universal Store.","adminLoginSlug":"store-admin","socialLinks":{"facebook":"https://facebook.com/","instagram":"https://instagram.com/","whatsapp":"+8801700000000"},"shippingAreas":[{"id":"inside-dhaka","name":"Inside Dhaka","charge":80,"estimate":"1–2 working days","active":true},{"id":"outside-dhaka","name":"Outside Dhaka","charge":140,"estimate":"2–5 working days","active":true},{"id":"remote","name":"Remote Area","charge":180,"estimate":"3–7 working days","active":true}],"paymentMethods":[{"id":"cod","name":"Cash on Delivery","enabled":true,"accountNumber":"","instructions":"Pay after receiving your order.","requiresTransactionId":false},{"id":"bkash","name":"bKash","enabled":true,"accountNumber":"01XXXXXXXXX","instructions":"Send payment and enter transaction ID.","requiresTransactionId":true},{"id":"nagad","name":"Nagad","enabled":false,"accountNumber":"01XXXXXXXXX","instructions":"Send payment and enter transaction ID.","requiresTransactionId":true}],"brandingBanners":[{"id":"banner-1","title":"Everyday Style, Elevated","subtitle":"Curated fashion and accessories for a polished everyday look.","image":"https://images.unsplash.com/photo-1445205170230-053b83016050?auto=format&fit=crop&w=1400&q=85","buttonText":"Explore Fashion","link":"/shop?category=cat-clothing","active":true},{"id":"banner-2","title":"Little Comforts","subtitle":"Soft essentials selected for babies and growing children.","image":"https://images.unsplash.com/photo-1522771930-78848d9293e8?auto=format&fit=crop&w=1400&q=85","buttonText":"Shop Baby","link":"/shop?category=cat-baby","active":true}],"newArrivalModels":[{"id":"model-1","title":"Modern Tailoring","subtitle":"Clean lines for the new season.","kicker":"New edit","image":"https://images.unsplash.com/photo-1506629082955-511b1aa562c8?auto=format&fit=crop&w=900&q=85","active":true},{"id":"model-2","title":"Everyday Ease","subtitle":"Relaxed layers and soft neutrals.","kicker":"Fresh look","image":"https://images.unsplash.com/photo-1529139574466-a303027c1d8b?auto=format&fit=crop&w=900&q=85","active":true},{"id":"model-3","title":"City Essentials","subtitle":"Confident style for busy days.","kicker":"Campaign","image":"https://images.unsplash.com/photo-1525507119028-ed4c629a60a3?auto=format&fit=crop&w=900&q=85","active":true},{"id":"model-4","title":"Weekend Edit","subtitle":"Simple, versatile and elevated.","kicker":"New season","image":"https://images.unsplash.com/photo-1534528741775-53994a69daeb?auto=format&fit=crop&w=900&q=85","active":true}]}') ON DUPLICATE KEY UPDATE data=VALUES(data);
